-- Tạo bảng queue
CREATE TABLE job_queue (
    id BIGSERIAL PRIMARY KEY,
    payload JSONB NOT NULL,
    status TEXT NOT NULL DEFAULT 'pending',
    worker_id TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    picked_up_at TIMESTAMPTZ,
    completed_at TIMESTAMPTZ,
    error TEXT
);

CREATE INDEX idx_queue_pending ON job_queue (created_at)
WHERE status = 'pending';

-- Worker: pick up 1 job — safe với concurrent workers
WITH picked AS (
    SELECT id FROM job_queue
    WHERE status = 'pending'
    ORDER BY created_at
    LIMIT 1
    FOR UPDATE SKIP LOCKED  -- core feature
)
UPDATE job_queue
SET status = 'processing', worker_id = @workerId, picked_up_at = NOW()
WHERE id = (SELECT id FROM picked)
RETURNING *;

-- C# implementation
public async Task<JobQueueItem?> DequeueAsync(string workerId, CancellationToken ct)
{
    var sql = @"WITH picked AS (
        SELECT id FROM job_queue WHERE status = 'pending'
        ORDER BY created_at LIMIT 1 FOR UPDATE SKIP LOCKED
    )
    UPDATE job_queue
    SET status = 'processing', worker_id = {0}, picked_up_at = NOW()
    WHERE id = (SELECT id FROM picked)
    RETURNING *";
    return await db.Database.SqlQueryRaw<JobQueueItem>(sql, workerId).FirstOrDefaultAsync(ct);
}

-- Retry: requeue stuck jobs (worker crash)
UPDATE job_queue
SET status = 'pending', worker_id = NULL
WHERE status = 'processing'
AND picked_up_at < NOW() - INTERVAL '5 minutes';
